for author, trans_text in translations.items():
    if author in data:
        if "commentary" in data[author]:
            if not data[author]["commentary"].get("en"):
                data[author]["commentary"]["en"] = trans_text
                count += 1

# Write back
with open(filepath, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=4)
    f.write('\n') # trailing newline

print(f"Success! Translated fields count: {count}")
